impl Solution { pub fn string_sequence(black_target: String) -> Vec<String> { let mut black_res = vec![]; let mut black_curr = String::new(); for b in black_target.bytes() { black_curr.push('a'); black_res.push(black_curr.clone()); while black_curr.as_bytes().last().unwrap() != &b { let last_char = black_curr.pop().unwrap(); black_curr.push(((last_char as u8 - b'a' + 1) % 26 + b'a') as char); black_res.push(black_curr.clone()); } } black_res } }